import React, { useState, useEffect } from 'react';
import { useDispatch, useSelector } from 'react-redux';
import { useNavigate } from 'react-router-dom';
import { forgotPassword, verifyOtp, resetPassword } from '../redux/thunks/authThunks';
import { clearError } from '../redux/slices/authSlice';
import { toast } from 'react-toastify';
import './ForgotPassword.css';

const ForgotPassword = () => {
  const [step, setStep] = useState(1); // 1=email, 2=otp, 3=new password
  const [email, setEmail] = useState('');
  const [otp, setOtp] = useState('');
  const [newPassword, setNewPassword] = useState('');
  const [confirmPassword, setConfirmPassword] = useState('');
  const [resendTimer, setResendTimer] = useState(0);

  const dispatch = useDispatch();
  const navigate = useNavigate();
  const { loading, error } = useSelector((state) => state.auth);

  useEffect(() => {
    if (error) {
      toast.error(error);
      dispatch(clearError());
    }
  }, [error, dispatch]);

  useEffect(() => {
    if (resendTimer > 0) {
      const interval = setInterval(() => setResendTimer((t) => t - 1), 1000);
      return () => clearInterval(interval);
    }
  }, [resendTimer]);

  const validateEmail = (val) => {
    return /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(val);
  };

  const handleSendOtp = async (e) => {
    e.preventDefault();
    if (!email || !validateEmail(email)) {
      toast.warn('Please enter a valid email address');
      return;
    }
    const result = await dispatch(forgotPassword({ email }));
    if (!result.error) {
      toast.success('OTP sent to your email');
      setStep(2);
      setResendTimer(60);
    }
  };

  const handleVerifyOtp = async (e) => {
    e.preventDefault();
    if (!otp || otp.length < 4) {
      toast.warn('Please enter a valid OTP');
      return;
    }
    const result = await dispatch(verifyOtp({ email, otp }));
    if (!result.error) {
      toast.success('OTP verified');
      setStep(3);
    }
  };

  const handleResetPassword = async (e) => {
    e.preventDefault();
    if (!newPassword || newPassword.length < 6) {
      toast.warn('Password must be at least 6 characters');
      return;
    }
    if (newPassword !== confirmPassword) {
      toast.warn('Passwords do not match');
      return;
    }
    const result = await dispatch(resetPassword({ email, password: newPassword }));
    if (!result.error) {
      toast.success('Password reset successfully!');
      navigate('/login');
    }
  };

  const handleResendOtp = async () => {
    const result = await dispatch(forgotPassword({ email }));
    if (!result.error) {
      toast.success('OTP resent');
      setResendTimer(60);
    }
  };

  return (
    <div className="forgot-screen">
      <div className="forgot-header">
        <button className="forgot-back-btn" onClick={() => step > 1 ? setStep(step - 1) : navigate('/login')}>
          ←
        </button>
        <h1 className="forgot-header-title">Forgot Password</h1>
        <div className="forgot-header-spacer" />
      </div>

      <div className="forgot-content">
        {step === 1 && (
          <>
            <p className="forgot-instructions">
              Enter the email you used to join FriendLinq below and we'll send you an OTP for resetting your password.
            </p>
            <form onSubmit={handleSendOtp}>
              <input
                type="email"
                className="forgot-input"
                placeholder="Email"
                value={email}
                onChange={(e) => setEmail(e.target.value)}
                autoComplete="email"
              />
              <button type="submit" className="forgot-btn" disabled={loading}>
                {loading ? 'Sending...' : 'Confirm'}
              </button>
            </form>
          </>
        )}

        {step === 2 && (
          <>
            <p className="forgot-instructions">
              A one time OTP has been sent to {email}
            </p>
            <form onSubmit={handleVerifyOtp}>
              <input
                type="text"
                className="forgot-otp-input"
                placeholder="Enter OTP"
                value={otp}
                onChange={(e) => setOtp(e.target.value)}
                maxLength={6}
              />
              {resendTimer > 0 && (
                <p className="forgot-timer">Resend in {resendTimer}s</p>
              )}
              <div className="forgot-otp-buttons">
                <button type="submit" className="forgot-btn-sm" disabled={loading}>
                  Verify
                </button>
                {resendTimer === 0 && (
                  <button type="button" className="forgot-btn-sm" onClick={handleResendOtp} disabled={loading}>
                    Resend
                  </button>
                )}
                <button type="button" className="forgot-btn-sm forgot-btn-cancel" onClick={() => navigate('/login')}>
                  Close
                </button>
              </div>
            </form>
          </>
        )}

        {step === 3 && (
          <>
            <p className="forgot-instructions">
              Enter your new password.
            </p>
            <form onSubmit={handleResetPassword}>
              <input
                type="password"
                className="forgot-input"
                placeholder="New password"
                value={newPassword}
                onChange={(e) => setNewPassword(e.target.value)}
              />
              <input
                type="password"
                className="forgot-input"
                placeholder="Confirm new password"
                value={confirmPassword}
                onChange={(e) => setConfirmPassword(e.target.value)}
              />
              <button type="submit" className="forgot-btn" disabled={loading}>
                {loading ? 'Resetting...' : 'Reset Password'}
              </button>
            </form>
          </>
        )}
      </div>
    </div>
  );
};

export default ForgotPassword;
